(function(){
  const svg = document.getElementById('loc-chart');
  const data = BUNDLE.monthly_loc;
  const W = 780, H = 260;
  const ML = 42, MR = 16, MT = 20, MB = 40;
  const pW = W - ML - MR, pH = H - MT - MB;
  const maxV = Math.max(...data.map(m => m.pct));
  const yMax = Math.ceil(maxV / 5) * 5;
  const n = data.length;
  const xS = i => ML + (i/(n-1)) * pW;
  const yS = v => MT + pH - (v/yMax) * pH;
  const ns = 'http://www.w3.org/2000/svg';
  const el = (name, a, t) => {
    const e = document.createElementNS(ns, name);
    for (const k in a) e.setAttribute(k, a[k]);
    if (t != null) e.textContent = t;
    return e;
  };
  for (let i = 0; i <= 4; i++) {
    const v = (yMax/4) * i, y = yS(v);
    svg.appendChild(el('line', {x1: ML, x2: ML+pW, y1: y, y2: y, stroke: '#d9ccb0', 'stroke-width': 1}));
    svg.appendChild(el('text', {x: ML-6, y: y+4, 'text-anchor': 'end',
        'font-family': 'var(--body)', 'font-size': 10.5, fill: '#6b5d4a'}, v.toFixed(0)+'%'));
  }
  data.forEach((m, i) => {
    if (m.YearMonth.endsWith('-01')) {
      const x = xS(i);
      svg.appendChild(el('line', {x1: x, x2: x, y1: MT+pH, y2: MT+pH+4, stroke: '#6b5d4a'}));
      svg.appendChild(el('text', {x: x, y: MT+pH+16, 'text-anchor': 'middle',
          'font-family': 'var(--body)', 'font-size': 10.5, fill: '#6b5d4a'}, m.YearMonth.slice(0,4)));
    }
  });
  const path = data.map((m,i) => (i===0?'M':'L')+xS(i)+','+yS(m.pct)).join(' ');
  svg.appendChild(el('path', {d: path, fill: 'none', stroke: '#7d1416', 'stroke-width': 1.8}));
  // Mark Jan 2025
  const ci = data.findIndex(m => m.YearMonth === '2025-01');
  if (ci > -1) {
    const cx = xS(ci);
    svg.appendChild(el('line', {x1: cx, x2: cx, y1: MT, y2: MT+pH,
        stroke: '#7d1416', 'stroke-width': 1.2, 'stroke-dasharray': '4 4', 'opacity': 0.7}));
    svg.appendChild(el('text', {x: cx+6, y: MT+14, 'font-family': 'var(--body)',
        'font-size': 10.5, fill: '#7d1416', 'font-weight': 700}, 'Jan 2025'));
  }
  svg.appendChild(el('line', {x1: ML, x2: ML+pW, y1: MT+pH, y2: MT+pH, stroke: '#6b5d4a'}));
  svg.appendChild(el('line', {x1: ML, x2: ML, y1: MT, y2: MT+pH, stroke: '#6b5d4a'}));
})();

